"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[717],{1725:(n,e,o)=>{o.d(e,{Y:()=>a});var t=o(5155),u=o(4824);function a(n){let{showBack:e,onBack:o,title:a}=n,{lang:s,setLang:i,dark:r,setDark:l,streak:d}=(0,u.Pj)();return e&&a?(0,t.jsxs)("div",{style:{display:"flex",alignItems:"center",gap:12,padding:"16px 20px 8px",position:"sticky",top:0,zIndex:20,background:"var(--nav-bg)",backdropFilter:"blur(12px)",borderBottom:"1px solid var(--card-border)"},children:[(0,t.jsx)("button",{onClick:o,style:{fontSize:20,color:"var(--text)",background:"none",border:"none",cursor:"pointer",padding:"4px 8px"},children:"←"}),(0,t.jsx)("span",{style:{fontSize:17,fontWeight:800,flex:1},children:a})]}):(0,t.jsxs)("div",{style:{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"16px 20px 8px",position:"sticky",top:0,zIndex:20,background:"var(--nav-bg)",backdropFilter:"blur(12px)"},children:[(0,t.jsxs)("div",{style:{display:"flex",alignItems:"center",gap:8},children:[(0,t.jsx)("span",{style:{fontFamily:"var(--font-space-mono), monospace",fontSize:22,fontWeight:700,background:"var(--gradient)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",backgroundClip:"text"},children:"ČESKY"}),(0,t.jsx)("span",{style:{fontSize:10,color:"var(--text2)",marginTop:4},children:"ua"===s?"Чеська для слов'ян":"Чешский для славян"})]}),(0,t.jsxs)("div",{style:{display:"flex",alignItems:"center",gap:10},children:[(0,t.jsx)("button",{onClick:()=>i("ua"===s?"ru":"ua"),style:{fontSize:12,fontWeight:700,color:"var(--accent)",padding:"4px 10px",border:"1.5px solid var(--accent)",borderRadius:8,background:"none",cursor:"pointer",fontFamily:"inherit"},children:"ua"===s?"УКР":"РУС"}),(0,t.jsx)("button",{onClick:()=>{let n=!r;l(n),document.documentElement.setAttribute("data-theme",n?"dark":"light")},style:{fontSize:18,background:"none",border:"none",cursor:"pointer",lineHeight:1},children:r?"☀️":"\uD83C\uDF19"}),(0,t.jsxs)("div",{style:{display:"flex",alignItems:"center",gap:3,color:"var(--accent)"},children:[(0,t.jsx)("span",{style:{fontSize:16},children:"\uD83D\uDD25"}),(0,t.jsx)("span",{style:{fontSize:13,fontWeight:800},children:d})]})]})]})}},2800:(n,e,o)=>{o.d(e,{p:()=>t,z:()=>u});let t={cases:{title_ua:"Чеські відмінки (P\xe1dy)",title_ru:"Чешские падежи (P\xe1dy)",icon:"\uD83C\uDFF7️",color:"#3b82f6",content_ua:"Чеська мова має **7 відмінків** — як і українська! Це велика перевага.\n\n\uD83D\uDFE2 **1. Nominativ** — Називний (Хто? Що?)\nKdo je to? — To je **student**.\n\uD83D\uDC49 Як \xabстудент\xbb у початковій формі.\n\n\uD83D\uDD35 **2. Genitiv** — Родовий (Кого? Чого?)\nNem\xe1m **studenta**. (Немає студента)\n\uD83D\uDC49 Часто замість \xabнемає\xbb + чого/кого.\n\n\uD83D\uDFE1 **3. Dativ** — Давальний (Кому? Чому?)\nD\xe1m to **studentovi**. (Дам студентові)\n\uD83D\uDC49 Кому щось дають або призначають.\n\n\uD83D\uDFE0 **4. Akuzativ** — Знахідний (Кого? Що?)\nVid\xedm **studenta**. (Бачу студента)\n\uD83D\uDC49 Прямий об'єкт дії.\n\n\uD83D\uDD34 **5. Vokativ** — Кличний (як звернення)\n**Studente!** (Студенте!)\n\uD83D\uDC49 В укр. теж є — \xabСтуденте!\xbb\n\n\uD83D\uDFE3 **6. Lok\xe1l** — Місцевий (Про кого? Де?)\nMluv\xedm o **studentovi**. (Говорю про студента)\n\uD83D\uDC49 Завжди з прийменником!\n\n⚫ **7. Instrument\xe1l** — Орудний (Ким? Чим?)\nJsem **studentem**. (Я є студентом)\n\uD83D\uDC49 Як \xabстудентом\xbb по-українськи.\n\n\uD83D\uDCA1 **Порада:** Роди в чеській та українській часто збігаються! Використовуйте це.",content_ru:"Чешский язык имеет **7 падежей** — на один больше, чем в русском (есть звательный).\n\n\uD83D\uDFE2 **1. Nominativ** — Именительный (Кто? Что?)\nKdo je to? — To je **student**.\n\uD83D\uDC49 Как \xabстудент\xbb в начальной форме.\n\n\uD83D\uDD35 **2. Genitiv** — Родительный (Кого? Чего?)\nNem\xe1m **studenta**. (Нет студента)\n\uD83D\uDC49 Часто после \xabнет\xbb + кого/чего.\n\n\uD83D\uDFE1 **3. Dativ** — Дательный (Кому? Чему?)\nD\xe1m to **studentovi**. (Дам студенту)\n\uD83D\uDC49 Кому что-то дают.\n\n\uD83D\uDFE0 **4. Akuzativ** — Винительный (Кого? Что?)\nVid\xedm **studenta**. (Вижу студента)\n\uD83D\uDC49 Прямой объект действия.\n\n\uD83D\uDD34 **5. Vokativ** — Звательный (обращение)\n**Studente!** (Студент!)\n\uD83D\uDC49 В русском нет! Как украинское \xabСтуденте!\xbb\n\n\uD83D\uDFE3 **6. Lok\xe1l** — Предложный (О ком? Где?)\nMluv\xedm o **studentovi**. (Говорю о студенте)\n\uD83D\uDC49 Всегда с предлогом!\n\n⚫ **7. Instrument\xe1l** — Творительный (Кем? Чем?)\nJsem **studentem**. (Я являюсь студентом)\n\uD83D\uDC49 Как \xabстудентом\xbb по-русски.\n\n\uD83D\uDCA1 **Совет:** Используйте знание русских падежей — они помогут понять чешские!",quiz:[{question_ua:"Який відмінок: \xabVid\xedm studenta\xbb?",question_ru:"Какой падеж: \xabVid\xedm studenta\xbb?",options:["Nominativ","Genitiv","Akuzativ","Dativ"],correct:2},{question_ua:"Скільки відмінків у чеській мові?",question_ru:"Сколько падежей в чешском языке?",options:["5","6","7","8"],correct:2}]},genders:{title_ua:"Роди іменників (Rod)",title_ru:"Роды существительных (Rod)",icon:"⚡",color:"#a855f7",content_ua:"Чеська мова має **3 роди** — як і українська:\n\n\uD83D\uDD35 **Mužsk\xfd rod (m)** — Чоловічий\nЗакінчення: приголосна\n✅ **student** (студент), **dům** (дім), **bratr** (брат)\n\uD83D\uDC49 Порівняй: студент, дім, брат — ті самі!\n\n\uD83D\uDD34 **Žensk\xfd rod (ž)** — Жіночий\nЗакінчення: **-a**, **-e**\n✅ **žena** (жінка), **škola** (школа), **ulice** (вулиця)\n\uD83D\uDC49 Порівняй: жінка, школа, вулиця\n\n\uD83D\uDFE2 **Středn\xed rod (s)** — Середній\nЗакінчення: **-o**, **-\xed**, **-ě**\n✅ **město** (місто), **moře** (море), **kuře** (курча)\n\uD83D\uDC49 Порівняй: місто, море, курча\n\n\uD83D\uDCA1 **Велика підказка:** Роди в чеській та українській часто збігаються!\n**město** = місто (обидва середній рід)\n**žena** = жінка (обидва жіночий)\n**bratr** = брат (обидва чоловічий)\n\n⚠️ **Увага:** Чоловічий рід ділиться на \xabживий\xbb і \xabнеживий\xbb:\n**živ\xfd** (живий): student, bratr → відмінювання інше!\n**neživ\xfd** (неживий): dům, stůl → відмінювання інше!",content_ru:"Чешский язык имеет **3 рода** — как и русский:\n\n\uD83D\uDD35 **Mužsk\xfd rod (m)** — Мужской\nОкончание: согласная\n✅ **student** (студент), **dům** (дом), **bratr** (брат)\n\uD83D\uDC49 Сравни: студент, дом, брат — те же!\n\n\uD83D\uDD34 **Žensk\xfd rod (ž)** — Женский\nОкончание: **-a**, **-e**\n✅ **žena** (женщина), **škola** (школа), **ulice** (улица)\n\uD83D\uDC49 Сравни: женщина, школа, улица\n\n\uD83D\uDFE2 **Středn\xed rod (s)** — Средний\nОкончание: **-o**, **-\xed**, **-ě**\n✅ **město** (город/место), **moře** (море), **kuře** (цыплёнок)\n\uD83D\uDC49 Сравни: место, море, цыплёнок\n\n\uD83D\uDCA1 **Важная подсказка:** Роды в чешском и русском часто совпадают!\n**město** = место/город (оба среднего рода)\n**žena** = женщина (оба женского)\n**bratr** = брат (оба мужского)\n\n⚠️ **Внимание:** Мужской род делится на \xabодушевлённый\xbb и \xabнеодушевлённый\xbb:\n**živ\xfd** (одушевлённый): student, bratr → склонение особое!\n**neživ\xfd** (неодушевлённый): dům, stůl → склонение особое!",quiz:[{question_ua:"Якого роду \xabškola\xbb (школа)?",question_ru:"Какого рода \xabškola\xbb (школа)?",options_ua:["Чоловічого","Жіночого","Середнього"],options_ru:["Мужского","Женского","Среднего"],correct:1},{question_ua:"Якого роду \xabměsto\xbb (місто)?",question_ru:"Какого рода \xabměsto\xbb (место/город)?",options_ua:["Чоловічого","Жіночого","Середнього"],options_ru:["Мужского","Женского","Среднего"],correct:2}]},verbs:{title_ua:"Дієслово b\xfdt (бути)",title_ru:"Глагол b\xfdt (быть)",icon:"\uD83D\uDD04",color:"#22c55e",content_ua:"Найважливіше дієслово чеської мови: **b\xfdt** (бути)\n\n**Теперішній час (Př\xedtomn\xfd čas):**\n\n| Особа | Чеська | Українська |\n|-------|--------|------------|\n| J\xe1 (я) | **jsem** | я є |\n| Ty (ти) | **jsi** | ти є |\n| On/Ona/Ono | **je** | він/вона є |\n| My (ми) | **jsme** | ми є |\n| Vy (ви) | **jste** | ви є |\n| Oni (вони) | **jsou** | вони є |\n\n\uD83D\uDCA1 В чеській \xabbути\xbb використовується ЗАВЖДИ:\n**Jsem student.** = Я (є) студент.\n**Jsi unaven\xfd?** = Ти (є) втомлений?\n\n\uD83D\uDC49 В українській ми часто пропускаємо \xabє\xbb, а в чеській — ні!\n\n**Заперечення (Negace):**\nJsem → **Nejsem** (я не є)\nJe → **Nen\xed** (він/вона не є)\n\n**Приклади:**\n✅ Jsem z Ukrajiny. = Я з України.\n✅ Nejsem doma. = Я не вдома.\n✅ Kde jsi? = Де ти є?",content_ru:"Самый важный глагол чешского языка: **b\xfdt** (быть)\n\n**Настоящее время (Př\xedtomn\xfd čas):**\n\n| Лицо | Чешский | Русский |\n|------|---------|---------|\n| J\xe1 (я) | **jsem** | я есть |\n| Ty (ты) | **jsi** | ты есть |\n| On/Ona/Ono | **je** | он/она есть |\n| My (мы) | **jsme** | мы есть |\n| Vy (вы) | **jste** | вы есть |\n| Oni (они) | **jsou** | они есть |\n\n\uD83D\uDCA1 В чешском \xabбыть\xbb используется ВСЕГДА:\n**Jsem student.** = Я (есть) студент.\n**Jsi unaven\xfd?** = Ты (есть) уставший?\n\n\uD83D\uDC49 В русском мы опускаем \xabесть\xbb, а в чешском — нет!\n\n**Отрицание (Negace):**\nJsem → **Nejsem** (я не есть)\nJe → **Nen\xed** (он/она не есть)\n\n**Примеры:**\n✅ Jsem z Ruska. = Я из России.\n✅ Nejsem doma. = Я не дома.\n✅ Kde jsi? = Где ты есть?",quiz:[{question_ua:"Як сказати \xabми є\xbb чеською?",question_ru:"Как сказать \xabмы есть\xbb по-чешски?",options:["Jsem","Jste","Jsme","Jsou"],correct:2},{question_ua:"Як заперечити \xabJsem\xbb (я є)?",question_ru:"Как отрицать \xabJsem\xbb (я есть)?",options:["Nen\xed","Nejsem","Nejste","Nejsou"],correct:1}]},adjectives:{title_ua:"Прикметники (Př\xeddavn\xe1 jm\xe9na)",title_ru:"Прилагательные (Př\xeddavn\xe1 jm\xe9na)",icon:"\uD83C\uDFA8",color:"#f97316",content_ua:"Чеські прикметники узгоджуються з іменниками в **роді, числі та відмінку** — як в українській!\n\n**Закінчення прикметників:**\n\n\uD83D\uDD35 **Чоловічий рід (-\xfd/-\xed)**\ndobr\xfd student = хороший студент\nmodern\xed dům = сучасний будинок\n\n\uD83D\uDD34 **Жіночий рід (-\xe1/-\xed)**\ndobr\xe1 žena = хороша жінка\nmodern\xed škola = сучасна школа\n\n\uD83D\uDFE2 **Середній рід (-\xe9/-\xed)**\ndobr\xe9 město = хороше місто\nmodern\xed auto = сучасне авто\n\n**Поширені прикметники:**\n✅ **velk\xfd/velk\xe1/velk\xe9** = великий (як \xabвеликий\xbb!)\n✅ **mal\xfd/mal\xe1/mal\xe9** = маленький\n✅ **nov\xfd/nov\xe1/nov\xe9** = новий\n✅ **star\xfd/star\xe1/star\xe9** = старий\n✅ **hezk\xfd/hezk\xe1/hezk\xe9** = гарний/красивий\n✅ **dobr\xfd/dobr\xe1/dobr\xe9** = хороший/добрий\n\n\uD83D\uDCA1 Порада: \xabDobr\xfd den\xbb = \xabХороший (добрий) день\xbb — ось звідки це привітання!",content_ru:"Чешские прилагательные согласуются с существительными в **роде, числе и падеже** — как в русском!\n\n**Окончания прилагательных:**\n\n\uD83D\uDD35 **Мужской род (-\xfd/-\xed)**\ndobr\xfd student = хороший студент\nmodern\xed dům = современный дом\n\n\uD83D\uDD34 **Женский род (-\xe1/-\xed)**\ndobr\xe1 žena = хорошая женщина\nmodern\xed škola = современная школа\n\n\uD83D\uDFE2 **Средний род (-\xe9/-\xed)**\ndobr\xe9 město = хорошее место/город\nmodern\xed auto = современный автомобиль\n\n**Распространённые прилагательные:**\n✅ **velk\xfd/velk\xe1/velk\xe9** = большой (как \xabвеликий\xbb!)\n✅ **mal\xfd/mal\xe1/mal\xe9** = маленький\n✅ **nov\xfd/nov\xe1/nov\xe9** = новый\n✅ **star\xfd/star\xe1/star\xe9** = старый\n✅ **hezk\xfd/hezk\xe1/hezk\xe9** = красивый/хороший\n✅ **dobr\xfd/dobr\xe1/dobr\xe9** = хороший/добрый\n\n\uD83D\uDCA1 Совет: \xabDobr\xfd den\xbb = \xabХороший (добрый) день\xbb — вот откуда это приветствие!",quiz:[{question_ua:"Яке закінчення для жіночого роду \xabдобрий\xbb?",question_ru:"Какое окончание для женского рода \xabхороший\xbb?",options:["dobr\xfd","dobr\xe1","dobr\xe9","dobr\xe9m"],correct:1}]},wordOrder:{title_ua:"Порядок слів (Slovosled)",title_ru:"Порядок слов (Slovosled)",icon:"\uD83D\uDCDD",color:"#ec4899",content_ua:"Порядок слів у чеській досить гнучкий — **схоже на українську!**\n\n**Базовий порядок: Підмет → Присудок → Додаток**\n✅ **J\xe1** j\xedm **chleba**. = Я їм хліб.\n✅ **M\xe1ma** vař\xed **pol\xe9vku**. = Мама варить суп.\n\n**Питальні речення:**\nВ чеській питання часто утворюються інтонацією:\n✅ Mluv\xedš česky? = Ти говориш чеською?\n✅ Jsi student? = Ти (є) студент?\n\nАбо словом **Kde/Co/Kdo/Jak/Proč:**\n✅ **Kde** jsi? = Де ти?\n✅ **Co** děl\xe1š? = Що ти робиш?\n✅ **Jak** se jmenuješ? = Як тебе звуть?\n\n**Заперечення — ставиться перед дієсловом:**\n✅ **Ne**mluv\xedm česky. = Я не говорю чеською.\n✅ **Ne**j\xedm maso. = Я не їм м'ясо.\n\n\uD83D\uDCA1 Порівняй з українською — майже те саме! \xabЯ не їм м'ясо\xbb = \xabNej\xedm maso\xbb",content_ru:"Порядок слов в чешском довольно гибкий — **похоже на русский!**\n\n**Базовый порядок: Подлежащее → Сказуемое → Дополнение**\n✅ **J\xe1** j\xedm **chleba**. = Я ем хлеб.\n✅ **M\xe1ma** vař\xed **pol\xe9vku**. = Мама варит суп.\n\n**Вопросительные предложения:**\nВ чешском вопросы часто образуются интонацией:\n✅ Mluv\xedš česky? = Ты говоришь по-чешски?\n✅ Jsi student? = Ты (есть) студент?\n\nИли вопросительными словами **Kde/Co/Kdo/Jak/Proč:**\n✅ **Kde** jsi? = Где ты?\n✅ **Co** děl\xe1š? = Что ты делаешь?\n✅ **Jak** se jmenuješ? = Как тебя зовут?\n\n**Отрицание — ставится перед глаголом:**\n✅ **Ne**mluv\xedm česky. = Я не говорю по-чешски.\n✅ **Ne**j\xedm maso. = Я не ем мясо.\n\n\uD83D\uDCA1 Сравни с русским — почти то же самое! \xabЯ не ем мясо\xbb = \xabNej\xedm maso\xbb",quiz:[{question_ua:"Як заперечити \xabJ\xedm maso\xbb (Я їм м'ясо)?",question_ru:"Как отрицать \xabJ\xedm maso\xbb (Я ем мясо)?",options:["Maso j\xedm ne","Nej\xedm maso","J\xedm ne maso","Maso nej\xedm ne"],correct:1}]},prepositions:{title_ua:"Прийменники (Předložky)",title_ru:"Предлоги (Předložky)",icon:"\uD83D\uDD17",color:"#14b8a6",content_ua:"Чеські прийменники — часто схожі на українські!\n\n**Найважливіші прийменники:**\n\n\uD83D\uDCCD **Місце:**\n✅ **v** (у, в) → v Praze = у Празі\n✅ **na** (на) → na stole = на столі\n✅ **do** (до, в) → jdu do školy = йду до школи\n✅ **z** (з, із) → jsem z Ukrajiny = я з України\n✅ **u** (біля, у) → u okna = біля вікна\n\n⏱️ **Час:**\n✅ **v** + час → v 9 hodin = о 9 годині\n✅ **za** (через) → za hodinu = через годину\n✅ **po** (після) → po škole = після школи\n\n\uD83D\uDD04 **Рух:**\n✅ **do** (до) → jdu do obchodu = йду до магазину\n✅ **z** (з) → jdu z pr\xe1ce = йду з роботи\n✅ **přes** (через) → jdu přes park = йду через парк\n\n⚠️ **Важливо:** Прийменники вимагають певного відмінка!\n**do** → Genitiv (родовий)\n**v** → Lok\xe1l (місцевий)\n**na** → Akuzativ або Lok\xe1l",content_ru:"Чешские предлоги — часто похожи на русские!\n\n**Важнейшие предлоги:**\n\n\uD83D\uDCCD **Место:**\n✅ **v** (в, у) → v Praze = в Праге\n✅ **na** (на) → na stole = на столе\n✅ **do** (в, до) → jdu do školy = иду в школу\n✅ **z** (из, с) → jsem z Ruska = я из России\n✅ **u** (у, около) → u okna = у окна\n\n⏱️ **Время:**\n✅ **v** + время → v 9 hodin = в 9 часов\n✅ **za** (через) → za hodinu = через час\n✅ **po** (после) → po škole = после школы\n\n\uD83D\uDD04 **Движение:**\n✅ **do** (в, до) → jdu do obchodu = иду в магазин\n✅ **z** (из) → jdu z pr\xe1ce = иду с работы\n✅ **přes** (через) → jdu přes park = иду через парк\n\n⚠️ **Важно:** Предлоги требуют определённого падежа!\n**do** → Genitiv (родительный)\n**v** → Lok\xe1l (предложный)\n**na** → Akuzativ или Lok\xe1l",quiz:[{question_ua:"Який прийменник \xabв місті\xbb?",question_ru:"Какой предлог \xabв городе\xbb?",options:["do","z","v","na"],correct:2}]},pastTense:{title_ua:"Минулий час (Minul\xfd čas)",title_ru:"Прошедшее время (Minul\xfd čas)",icon:"⏪",color:"#6366f1",content_ua:"Минулий час у чеській утворюється просто — **схоже на українську!**\n\n**Утворення:**\nдієслово (інфінітив) → прибери **-t** → додай закінчення:\n\n| Рід | Закінчення | Приклад |\n|-----|-----------|---------|\n| чол. (j\xe1/ty/on) | **-l** | dělal (робив) |\n| жін. (j\xe1/ty/ona) | **-la** | dělala (робила) |\n| сер. (ono) | **-lo** | dělalo (робило) |\n| мн. (my/vy/oni) | **-li** | dělali (робили) |\n\n**Допоміжне дієслово (бути):**\n✅ J\xe1 **jsem dělal/dělala**. = Я робив/робила.\n✅ Ty **jsi dělal/dělala**. = Ти робив/робила.\n✅ On/Ona **dělal/dělala**. = Він/Вона робив/робила. (без допоміжного!)\n\n**Приклади:**\n✅ Včera jsem **pracoval**. = Вчора я працював.\n✅ Ona **šla** do školy. = Вона пішла до школи.\n✅ Jedli **jsme** pol\xe9vku. = Ми їли суп.\n\n\uD83D\uDCA1 Порівняй: \xabЯ робив\xbb = \xabJ\xe1 jsem dělal\xbb — майже те саме!",content_ru:"Прошедшее время в чешском образуется просто — **похоже на русский!**\n\n**Образование:**\nглагол (инфинитив) → убери **-t** → добавь окончание:\n\n| Род | Окончание | Пример |\n|-----|-----------|--------|\n| муж. (j\xe1/ty/on) | **-l** | dělal (делал) |\n| жен. (j\xe1/ty/ona) | **-la** | dělala (делала) |\n| ср. (ono) | **-lo** | dělalo (делало) |\n| мн.ч. (my/vy/oni) | **-li** | dělali (делали) |\n\n**Вспомогательный глагол (быть):**\n✅ J\xe1 **jsem dělal/dělala**. = Я делал/делала.\n✅ Ty **jsi dělal/dělala**. = Ты делал/делала.\n✅ On/Ona **dělal/dělala**. = Он/Она делал/делала. (без вспомогательного!)\n\n**Примеры:**\n✅ Včera jsem **pracoval**. = Вчера я работал.\n✅ Ona **šla** do školy. = Она пошла в школу.\n✅ Jedli **jsme** pol\xe9vku. = Мы ели суп.\n\n\uD83D\uDCA1 Сравни: \xabЯ делал\xbb = \xabJ\xe1 jsem dělal\xbb — почти то же самое!",quiz:[{question_ua:"Як сказати \xabвона працювала\xbb?",question_ru:"Как сказать \xabона работала\xbb?",options:["pracoval","pracovala","pracovalo","pracovali"],correct:1}]}},u=[{key:"cases",icon:"\uD83C\uDFF7️",color:"#3b82f6"},{key:"genders",icon:"⚡",color:"#a855f7"},{key:"verbs",icon:"\uD83D\uDD04",color:"#22c55e"},{key:"adjectives",icon:"\uD83C\uDFA8",color:"#f97316"},{key:"wordOrder",icon:"\uD83D\uDCDD",color:"#ec4899"},{key:"prepositions",icon:"\uD83D\uDD17",color:"#14b8a6"},{key:"pastTense",icon:"⏪",color:"#6366f1"}]},8342:(n,e,o)=>{o.d(e,{l:()=>r});var t=o(5155),u=o(63),a=o(4824),s=o(862);let i=[{path:"/",key:"home",icon:"\uD83C\uDFE0"},{path:"/learn",key:"learn",icon:"\uD83D\uDCDA"},{path:"/practice",key:"practice",icon:"\uD83C\uDFAF"},{path:"/chat",key:"chat",icon:"\uD83D\uDCAC"},{path:"/profile",key:"profile",icon:"\uD83D\uDC64"}];function r(){let n=(0,u.usePathname)(),e=(0,u.useRouter)(),o=(0,a.Pj)(n=>n.lang),r=s.L[o];return(0,t.jsx)("div",{style:{position:"fixed",bottom:0,left:"50%",transform:"translateX(-50%)",width:"100%",maxWidth:480,background:"var(--nav-bg)",backdropFilter:"blur(12px)",borderTop:"1px solid var(--card-border)",padding:"6px 12px 10px",display:"flex",zIndex:30},children:i.map(o=>{var u;let a="/"===(u=o.path)?"/"===n:n.startsWith(u),s=r[o.key];return(0,t.jsxs)("button",{className:"nav-item ".concat(a?"active":""),onClick:()=>e.push(o.path),children:[(0,t.jsx)("span",{style:{fontSize:20},children:o.icon}),(0,t.jsx)("span",{style:{fontSize:10,fontWeight:700},children:s})]},o.path)})})}}}]);